SELECT /* @SQLID=SUB020302_0101-03#Sql001 */ A.IFA_ORDER_NO AS ifaOrderNo, A.IFA_ORDER_SUB_NO AS ifaOrderSubNo, A.BUTEN_CODE AS butenCode, A.ACCOUNT_NUMBER AS accountNumber, B.NAME_KANJI AS customerNameKanji, B.NAME_KANA AS customerNameKana, A.TRADE_KBN AS tradeKbn, A.NORIKAE_YUGU_KBN AS norikaeYuguKbn, A.CHECK_COMP_WRN_ALERT AS checkCompWrnAlert, A.MOKUROMI_KOUFU_KBN AS mokuromiKoufuKbn, A.NORIKAE_KANYU_KBN AS norikaeKanyuKbn, A.RIEKISOUHAN AS conflictOfInterestExplain, A.CHECK_HIYOU AS checkHiyou, A.CHECK_FUKUSU AS checkFukusu, A.DOUITSU_TUKA_KUNI_KBN AS douitsuTukaKuniKbn, A.TASHA_NORIKAE_KBN AS tashaNorikaeKbn, A.TANKI_SELL_KBN AS tankiSellKbn, A.SHOKAN_MAE_KBN AS shokanMaeKbn, C.USER_ID AS userId, C.USER_NM AS userName FROM JP_TOUSHIN_ORDER A LEFT OUTER JOIN MEDIATE_USER_ATTRIBUTE_INFO B ON A.BUTEN_CODE = B.BUTEN_CODE AND A.ACCOUNT_NUMBER = B.ACCOUNT_NUMBER AND A.BROKER_CODE = B.BROKER_CODE LEFT JOIN TB_MED_USERS C ON A.CREATE_USER = C.USER_ID
AND 1 = 1
AND (A.BROKER_CODE IN
) OR A.BROKER_CODE IN(
,
#{brokerCharge.brokerCode}
)
AND ((A.BROKER_CODE, A.INTERMEDIARY_EMP_CD) IN
) OR (A.BROKER_CODE, A.INTERMEDIARY_EMP_CD) IN (
,
(#{brokerCharge.brokerCode}, #{brokerCharge.empCode})
)
AND A.IFA_ORDER_NO = #{req.ifaOrderNo} AND A.IFA_ORDER_SUB_NO = #{req.ifaOrderSubNo}
